REST_9_25 = None  # loaded below from separate module after write

def validate(strings):
    if len(strings) != 25:
        raise SystemExit(f"Expected 25 strings, got {len(strings)}")
    for i, s in enumerate(strings):
        bad = [c for c in s if c.isascii() and c.isalpha()]
        if bad:
            raise SystemExit(f"String {i+1} has Latin: {sorted(set(bad))} in: ...{s[:80]}...")

def main():
    from mitzvot_004_he_rest import REST_9_25 as REST
    head = [p.strip() for p in DATA.read_text(encoding="utf-8").split("\n---\n") if p.strip()]
    if len(head) != 5:
        raise SystemExit(f"Expected 5 head strings, got {len(head)}")
    all_strings = head + TAIL_6_8 + REST
    validate(all_strings)
    OUT.parent.mkdir(parents=True, exist_ok=True)
    OUT.write_text(json.dumps({"he": all_strings}, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(f"OK: wrote {len(all_strings)} strings to {OUT}")
    for i, s in enumerate(all_strings, 1):
        print(f"  {i}: {len(s)} chars")

if __name__ == "__main__":
    main()
